def _module_basename():
    path = ida_nalt.get_input_file_path() or ""
    return os.path.basename(path).lower()

def apply():
    base = idaapi.get_imagebase()
    module = _module_basename()
    renamed = 0
    commented = 0
    skipped_module = 0
    not_in_image = 0
    for name, mod, rva, resolve, sig_hash in SIGNATURES:
        if module and mod.lower() != module:
            skipped_module += 1
            continue
        ea = base + rva
        if not ida_bytes.is_loaded(ea):
            not_in_image += 1
            continue
        # Make sure IDA sees a function here so we can name + comment it.
        if ida_funcs.get_func(ea) is None:
            ida_funcs.add_func(ea)
        current = ida_name.get_ea_name(ea) or ""
        if not current or current.startswith("sub_") or current.startswith("loc_"):
            if ida_name.set_name(ea, name, ida_name.SN_NOWARN | ida_name.SN_FORCE):
                renamed += 1
        comment = "cs2-sdk: {} [{}, build={}, hash={}]".format(
            name, resolve, CS2_BUILD, sig_hash,
        )
        idaapi.set_cmt(ea, comment, True)
        commented += 1
    print("[cs2-sdk] applied {} signatures (renamed={}, commented={}, skipped_module={}, not_in_image={})".format(
        len(SIGNATURES), renamed, commented, skipped_module, not_in_image
    ))

apply()
